          poster: { type: "string", format: "uri", example: "https://image.tmdb.org/t/p/w500/..." },
          year: { type: "string", example: "2013" },
          rating: { type: "string", example: "9.1" },
          box_type: { type: "number", enum: [1, 2], description: "1 = Movie, 2 = TV Show" },
